from itertools import count
def ssd(n): # sum of squared digits
    return sum(int(d)**2 for d in str(n))
def is_happy(n):
    while n not in [1, 4]: n = ssd(n) # iterate until fixed point or in cycle
    return n==1
def a(n):
    return next(h for h in count(1) if is_happy(h) and is_happy(h*n))
print([a(n) for n in range(1, 69)]) # _Michael S. Branicky_, Jun 16 2026

